import{c as s,Q as a,j as i,m as t}from"./chunks/framework.B5EQ7QKW.js";const c=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{"title":"Getting Started"},"headers":[],"relativePath":"getting-started.md","filePath":"getting-started.md","lastUpdated":1782827813000}'),l={name:"getting-started.md"};function n(h,e,p,r,o,k){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>Thalamus is a vendor-neutral, Kubernetes-native inference service based on <a href="https://llm-d.ai/" target="_blank" rel="noreferrer">llm-d</a>, the <a href="https://github.com/kubernetes-sigs/gateway-api-inference-extension" target="_blank" rel="noreferrer">Gateway API inference extension</a>, and <a href="https://github.com/cobaltcore-dev/cortex" target="_blank" rel="noreferrer">Cortex</a>.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><h3 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools&quot;">​</a></h3><ul><li><a href="https://kubernetes.io/docs/tasks/tools/" target="_blank" rel="noreferrer">kubectl</a> — Kubernetes CLI</li><li><a href="https://helm.sh/docs/intro/install/" target="_blank" rel="noreferrer">helm</a> — Kubernetes package manager (v3.x)</li><li><a href="https://helmfile.readthedocs.io/en/latest/#installation" target="_blank" rel="noreferrer">helmfile</a> — declarative wrapper around helm (v1.x)</li><li>A Kubernetes cluster with GPU nodes (NVIDIA), or <a href="https://minikube.sigs.k8s.io/docs/start/" target="_blank" rel="noreferrer">minikube</a> / any other local cluster for development</li></ul><h3 id="accounts" tabindex="-1">Accounts <a class="header-anchor" href="#accounts" aria-label="Permalink to &quot;Accounts&quot;">​</a></h3><ul><li>A <a href="https://huggingface.co" target="_blank" rel="noreferrer">Hugging Face</a> account with a <a href="https://huggingface.co/settings/tokens" target="_blank" rel="noreferrer">read token</a> and access to the models you want to serve</li></ul><h2 id="step-1-—-create-the-hugging-face-secret" tabindex="-1">Step 1 — Create the Hugging Face secret <a class="header-anchor" href="#step-1-—-create-the-hugging-face-secret" aria-label="Permalink to &quot;Step 1 — Create the Hugging Face secret&quot;">​</a></h2><p>Thalamus pulls model weights from Hugging Face at pod startup. Create a secret with your Hugging Face token in the <code>thalamus</code> namespace:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> namespace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> thalamus</span></span></code></pre></div><p>Then create the secret. The chart expects a secret named <code>hf-token</code> with key <code>HF_TOKEN</code>.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secret</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> generic</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hf-token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --from-literal=HF_TOKEN=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HF_TOKEN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --namespace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> thalamus</span></span></code></pre></div><h2 id="step-2-—-create-api-key-secrets-optional" tabindex="-1">Step 2 — Create API key secrets (optional) <a class="header-anchor" href="#step-2-—-create-api-key-secrets-optional" aria-label="Permalink to &quot;Step 2 — Create API key secrets (optional)&quot;">​</a></h2><p>When <code>gateway.apiKeyAuth</code> is enabled, every request to the inference API must carry a valid <code>Authorization: Bearer &lt;token&gt;</code> header. Tokens are stored as Kubernetes Secrets labelled <code>thalamus-apikey: &quot;true&quot;</code>.</p><p>Create one secret per user or client:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secret</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> generic</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apikey-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --namespace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> thalamus</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --from-literal=api-key=$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rand</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -base64 32 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;+/&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;-_&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;=&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> label</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secret</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apikey-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --namespace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> thalamus</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> thalamus-apikey=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p>Open WebUI connects to the inference API internally and also requires a token. Set the following in your cluster values to point Open WebUI at the secret:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">open-webui</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  openaiApiKeyExistingSecret</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">apikey-openwebui</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  openaiApiKeyExistingSecretKey</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">api-key</span></span></code></pre></div><h2 id="step-3-—-deploy-the-stack" tabindex="-1">Step 3 — Deploy the stack <a class="header-anchor" href="#step-3-—-deploy-the-stack" aria-label="Permalink to &quot;Step 3 — Deploy the stack&quot;">​</a></h2><p>The <code>helm/helmfile.yaml.gotmpl</code> manifest installs the full stack as a set of ordered helmfile releases: the Gateway API and Inference Extension CRDs, the Thalamus CRDs, the GPU operator and node feature discovery, the agentgateway with its CRDs, <code>kube-prometheus-stack</code> for observability, the <code>thalamus</code> chart (operator + workloads: inference gateway, models, routes), and finally <code>open-webui</code>. Helmfile registers the required helm repositories and applies the releases in dependency order.</p><blockquote><p><strong>Thalamus operator — under development</strong></p><p>The Thalamus operator will automate model instance management and move model declaration from Helm values to the <code>thalamus.cloud/v1alpha1 Model</code> CRD, enabling fully declarative, per-resource lifecycle control. Until then, models are managed through the <code>models:</code> values key described below.</p></blockquote><p>Deploy with chart defaults:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">helmfile</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> helm/helmfile.yaml.gotmpl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span></span></code></pre></div><p>To customize values for your cluster, write a release-keyed values file and pass it via <code>--state-values-file</code>. The top-level keys are helmfile release names (e.g. <code>thalamus</code>, <code>open-webui</code>, <code>gpu-operator</code>, <code>kube-prometheus-stack</code>, <code>agentgateway</code>); everything underneath is forwarded to that release as chart values. See <a href="../helm/example.values.yaml"><code>example.values.yaml</code></a> for a reference shape of the <code>thalamus</code> release values.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># my-cluster.yaml</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">thalamus</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  models</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">slug</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">qwen3-6-27b</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      model</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Qwen/Qwen3.6-27B</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      accelerator</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nvidia</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      resources</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        requests</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">nvidia.com/gpu</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        limits</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:   { </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">nvidia.com/gpu</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">helmfile</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> helm/helmfile.yaml.gotmpl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --state-values-file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-cluster.yaml</span></span></code></pre></div><p>To preview changes before applying, use <code>helmfile diff</code> in place of <code>apply</code>.</p><p><strong>Caveats for values file:</strong></p><ul><li>Adjust <code>resources</code> for your selected model. If it fails without a visible error, it might be OOM-killed due to RAM overflowing the specified <code>limit</code>.</li><li>If your resources are limited, you may try setting up <code>&quot;--max-model-len=8192&quot;</code> under <code>baseArgs</code> and explore other options to optimize the model.</li><li>Model slugs must be valid DNS-1035 labels: lowercase alphanumeric and hyphens only, starting with a letter. Dots and underscores are not allowed (e.g. use <code>qwen3-0-6b</code>, not <code>qwen3-0.6b</code>).</li></ul><h2 id="step-4-—-access-the-stack" tabindex="-1">Step 4 — Access the stack <a class="header-anchor" href="#step-4-—-access-the-stack" aria-label="Permalink to &quot;Step 4 — Access the stack&quot;">​</a></h2><p>Once the pods are running, the stack is reachable in two ways.</p><h3 id="gateway-api-openai-compatible-endpoint" tabindex="-1">Gateway API (OpenAI-compatible endpoint) <a class="header-anchor" href="#gateway-api-openai-compatible-endpoint" aria-label="Permalink to &quot;Gateway API (OpenAI-compatible endpoint)&quot;">​</a></h3><p>The inference gateway exposes an OpenAI-compatible API. Use the <code>LoadBalancer</code> IP or internal service address to send requests:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gateway-i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/v1/chat/completions</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;model&quot;: &quot;Qwen/Qwen3.6-27B&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;messages&quot;: [{&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;Hello!&quot;}]</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  }&#39;</span></span></code></pre></div><p>For local clusters without a <code>LoadBalancer</code>, use port-forward:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> port-forward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> svc/inference-gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 8080:80</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> thalamus</span></span></code></pre></div><h3 id="open-webui" tabindex="-1">Open WebUI <a class="header-anchor" href="#open-webui" aria-label="Permalink to &quot;Open WebUI&quot;">​</a></h3><p><code>thalamus</code> includes <a href="https://github.com/open-webui/open-webui" target="_blank" rel="noreferrer">Open WebUI</a>, a browser-based chat interface. It is reachable via the hostname configured in your <code>open-webui.route.hostnames</code> value, or via port-forward for local access:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> port-forward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> svc/open-webui</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 8080:80</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> open-webui</span></span></code></pre></div><p>Then open <code>http://localhost:8080</code> in your browser.</p><h2 id="local-development-cpu-no-gpu" tabindex="-1">Local development (CPU, no GPU) <a class="header-anchor" href="#local-development-cpu-no-gpu" aria-label="Permalink to &quot;Local development (CPU, no GPU)&quot;">​</a></h2><p>The default model and config provided are for the GPU setup. If you want the most lightweight LLM deploy fast out of box on your laptop, replace the configuration with the commented one and choose CPU-based lightweight models.</p><blockquote><p><strong>Note:</strong> The CPU image has no Apple Silicon / Metal acceleration. Inference will be significantly slower than on a GPU or native macOS runtimes like Ollama. <strong>Note:</strong> When using the Docker driver (default on macOS), Docker does not fully virtualize memory — vLLM sees the entire host RAM and will attempt to allocate a large fraction of it, exceeding your container limits and causing an OOM kill. Set <code>--gpu-memory-utilization</code> explicitly to avoid this.</p></blockquote><p>Observed peak usage for small CPU models is ~8 cores and ~24–25 GiB RAM, driven primarily by KV cache pre-allocation rather than model size.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li>Browse the <a href="/thalamus/main/reference/model-crd-api">Model CRD API Reference</a> for all available fields.</li><li>Read about the <a href="/thalamus/main/concepts/architecture">planned architecture</a>.</li></ul>`,46)])])}const g=s(l,[["render",n]]);export{c as __pageData,g as default};
